export * from './tab-list.component';
export * from './tab-menu.component';
export * from './tab-panel.component';
export * from './tab.component';
export * from './tabs-indicator.directive';
export * from './tabs.base';
export * from './tabs.component';
export * from './tabs.variants';
export * from './tabs.token';
export * from './tabs.imports';

import { NgTemplateOutlet } from '@angular/common';
import {
  afterRenderEffect,
  ChangeDetectionStrategy,
  Component,
  computed,
  DestroyRef,
  effect,
  ElementRef,
  inject,
  input,
  signal,
  ViewEncapsulation,
  viewChild,
} from '@angular/core';
import { NgIcon, provideIcons } from '@ng-icons/core';
import {
  phosphorCaretDown,
  phosphorCaretLeft,
  phosphorCaretRight,
  phosphorCaretUp,
} from '@ng-icons/phosphor-icons/regular';

import { cn, type ClassValue } from '{{alias}}/utils';
import { HB_TABS, type HbTabsContext } from './tabs.token';
import { tabListVariants } from './tabs.variants';

@Component({
  selector: 'hb-tab-list',
  imports: [NgIcon, NgTemplateOutlet],
  viewProviders: [
    provideIcons({ phosphorCaretLeft, phosphorCaretRight, phosphorCaretUp, phosphorCaretDown }),
  ],
  template: `
    @if (ctx.showArrows() && canStart()) {
      <button type="button" class="hb-tab-arrow" aria-label="Scroll back" (click)="scroll(-1)">
        <ng-icon [name]="horizontal() ? 'phosphorCaretLeft' : 'phosphorCaretUp'" />
      </button>
    }

    <div #scrollport [class]="scrollClasses()" (scroll)="updateOverflow()">
      <div #inner [class]="innerClasses()">
        <ng-content />
        @if (indVisible()) {
          <span
            [class]="indicatorClasses()"
            [style.left.px]="indLeft()"
            [style.top.px]="indTop()"
            [style.width.px]="indWidth()"
            [style.height.px]="indHeight()"
          >
            @if (ctx.indicatorTemplate(); as tpl) {
              <ng-container [ngTemplateOutlet]="tpl" />
            }
          </span>
        }
      </div>
    </div>

    @if (ctx.showArrows() && canEnd()) {
      <button type="button" class="hb-tab-arrow" aria-label="Scroll forward" (click)="scroll(1)">
        <ng-icon [name]="horizontal() ? 'phosphorCaretRight' : 'phosphorCaretDown'" />
      </button>
    }
  `,
  styles: `
    .hb-tab-arrow {
      display: inline-flex;
      flex-shrink: 0;
      align-items: center;
      justify-content: center;
      align-self: center;
      width: 1.75rem;
      height: 1.75rem;
      border-radius: calc(var(--radius) - 2px);
      color: var(--muted-foreground);
      cursor: pointer;
    }
    .hb-tab-arrow:hover {
      background: var(--muted);
      color: var(--foreground);
    }
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    role: 'tablist',
    '[class]': 'hostClasses()',
    '[attr.aria-orientation]': 'ctx.orientation()',
    '[attr.data-slot]': "'tab-list'",
  },
  exportAs: 'hbTabList',
})
export class HbTabListComponent {
  protected readonly ctx = inject<HbTabsContext>(HB_TABS);
  private readonly destroyRef = inject(DestroyRef);
  private readonly scrollEl = viewChild.required<ElementRef<HTMLElement>>('scrollport');
  private readonly innerEl = viewChild.required<ElementRef<HTMLElement>>('inner');

  readonly class = input<ClassValue>('');

  protected readonly horizontal = computed(() => this.ctx.orientation() === 'horizontal');
  protected readonly scrollMode = computed(() => {
    const threshold = this.ctx.scrollThreshold();
    return this.ctx.showArrows() || (threshold > 0 && this.ctx.triggers().length > threshold);
  });

  protected readonly indLeft = signal<number | null>(null);
  protected readonly indTop = signal<number | null>(null);
  protected readonly indWidth = signal<number | null>(null);
  protected readonly indHeight = signal<number | null>(null);
  protected readonly indVisible = signal(false);
  protected readonly canStart = signal(false);
  protected readonly canEnd = signal(false);
  private readonly resizeTick = signal(0);

  private readonly trackBorder = computed(() => {
    if (this.ctx.variant() === 'pills') return '';
    return {
      top: 'border-b border-border',
      bottom: 'border-t border-border',
      left: 'border-r border-border',
      right: 'border-l border-border',
    }[this.ctx.position()];
  });

  protected readonly hostClasses = computed(() =>
    cn(
      'relative flex',
      this.horizontal() ? 'flex-row items-stretch' : 'flex-col items-stretch',
      this.trackBorder(),
      this.class(),
    ),
  );
  protected readonly scrollClasses = computed(() =>
    cn(
      'min-h-0 min-w-0 flex-1',
      this.scrollMode() ? 'hb-scrollbar-none overflow-auto' : 'overflow-visible',
    ),
  );
  protected readonly innerClasses = computed(() =>
    cn(
      tabListVariants({
        orientation: this.ctx.orientation(),
        variant: this.ctx.variant(),
        align: this.ctx.align(),
      }),
      this.scrollMode()
        ? this.horizontal()
          ? 'w-max flex-nowrap'
          : 'h-max flex-nowrap'
        : this.horizontal()
          ? 'w-full flex-wrap'
          : 'h-full flex-wrap',
    ),
  );
  protected readonly indicatorClasses = computed(() =>
    cn(
      'pointer-events-none absolute transition-all duration-200 ease-out',
      this.ctx.variant() === 'pills'
        ? 'z-0 rounded-md bg-background shadow-sm'
        : 'z-0 rounded-full bg-primary',
      this.ctx.indicatorClass(),
    ),
  );

  constructor() {
    afterRenderEffect(() => {
      this.ctx.value();
      this.ctx.triggers();
      this.ctx.variant();
      this.ctx.position();
      this.resizeTick();
      this.measure();
      this.updateOverflow();
    });

    const RO = (globalThis as { ResizeObserver?: typeof ResizeObserver }).ResizeObserver;
    const ro = RO ? new RO(() => this.resizeTick.update((v) => v + 1)) : null;
    effect(() => {
      const inner = this.innerEl().nativeElement;
      ro?.observe(inner);
    });
    this.destroyRef.onDestroy(() => ro?.disconnect());
  }

  private measure(): void {
    const active = this.ctx.triggers().find((t) => this.ctx.isActive(t.value()));
    if (!active) {
      this.indVisible.set(false);
      return;
    }
    const el = active.element();
    let left = el.offsetLeft;
    let top = el.offsetTop;
    let width = el.offsetWidth;
    let height = el.offsetHeight;
    if (this.ctx.variant() !== 'pills') {
      const th = this.ctx.variant() === 'underline' ? 3 : 2;
      const pos = this.ctx.position();
      if (pos === 'top') {
        top = el.offsetTop + el.offsetHeight - th;
        height = th;
      } else if (pos === 'bottom') {
        height = th;
      } else if (pos === 'left') {
        left = el.offsetLeft + el.offsetWidth - th;
        width = th;
      } else {
        width = th;
      }
    }
    this.indLeft.set(left);
    this.indTop.set(top);
    this.indWidth.set(width);
    this.indHeight.set(height);
    this.indVisible.set(true);
  }

  protected updateOverflow(): void {
    const el = this.scrollEl().nativeElement;
    if (this.horizontal()) {
      this.canStart.set(el.scrollLeft > 1);
      this.canEnd.set(el.scrollLeft + el.clientWidth < el.scrollWidth - 1);
    } else {
      this.canStart.set(el.scrollTop > 1);
      this.canEnd.set(el.scrollTop + el.clientHeight < el.scrollHeight - 1);
    }
  }

  protected scroll(direction: number): void {
    const el = this.scrollEl().nativeElement;
    const amount = (this.horizontal() ? el.clientWidth : el.clientHeight) * 0.7 * direction;
    el.scrollBy(
      this.horizontal() ? { left: amount, behavior: 'smooth' } : { top: amount, behavior: 'smooth' },
    );
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  forwardRef,
  ViewEncapsulation,
} from '@angular/core';

import { HbTabListComponent } from './tab-list.component';
import { HbTabsBase } from './tabs.base';
import { HB_TABS } from './tabs.token';

@Component({
  selector: 'hb-tab-menu',
  imports: [HbTabListComponent],
  template: `<hb-tab-list [class]="class()"><ng-content /></hb-tab-list>`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: { class: 'block', '[attr.data-slot]': "'tab-menu'" },
  providers: [{ provide: HB_TABS, useExisting: forwardRef(() => HbTabMenuComponent) }],
  exportAs: 'hbTabMenu',
})
export class HbTabMenuComponent extends HbTabsBase {}

import {
  booleanAttribute,
  ChangeDetectionStrategy,
  Component,
  computed,
  effect,
  inject,
  input,
  signal,
  ViewEncapsulation,
} from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import { HB_TABS, type HbTabsContext } from './tabs.token';

@Component({
  selector: 'hb-tab-panel',
  template: `
    @if (!hbLazy() || rendered()) {
      <ng-content />
    }
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    role: 'tabpanel',
    '[class]': 'classes()',
    '[id]': 'ctx?.panelId(hbValue())',
    '[attr.aria-labelledby]': 'ctx?.tabId(hbValue())',
    '[hidden]': '!active()',
    '[attr.tabindex]': 'active() ? 0 : null',
    '[attr.data-slot]': "'tab-panel'",
  },
  exportAs: 'hbTabPanel',
})
export class HbTabPanelComponent {
  protected readonly ctx = inject<HbTabsContext | null>(HB_TABS, { optional: true });

  readonly hbValue = input<unknown>(null);
  readonly hbLazy = input(false, { transform: booleanAttribute });
  readonly class = input<ClassValue>('');

  protected readonly active = computed(() => (this.ctx ? this.ctx.isActive(this.hbValue()) : false));
  protected readonly rendered = signal(false);

  private readonly spacing = computed(() => {
    switch (this.ctx?.position()) {
      case 'bottom':
        return 'mb-3';
      case 'left':
        return 'ml-4';
      case 'right':
        return 'mr-4';
      default:
        return 'mt-3';
    }
  });
  protected readonly classes = computed(() =>
    cn('min-w-0 flex-1 outline-none', this.spacing(), this.class()),
  );

  constructor() {
    effect(() => {
      if (this.active()) this.rendered.set(true);
    });
  }
}

import {
  booleanAttribute,
  ChangeDetectionStrategy,
  Component,
  computed,
  DestroyRef,
  ElementRef,
  inject,
  input,
  ViewEncapsulation,
} from '@angular/core';
import { NgIcon } from '@ng-icons/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import { HB_TABS, type HbTabsContext, type HbTabTriggerRef } from './tabs.token';
import { tabTriggerVariants } from './tabs.variants';

@Component({
  selector: 'hb-tab',
  imports: [NgIcon],
  template: `
    @if (hbIcon()) {
      <ng-icon [name]="hbIcon()" />
    }
    <ng-content />
    @if (hbBadge() !== null && hbBadge() !== '') {
      <span
        class="ml-1 inline-flex min-w-4 items-center justify-center rounded-full bg-muted px-1 text-[0.625rem] leading-none data-[state=active]:bg-primary/10"
        [attr.data-state]="active() ? 'active' : 'inactive'"
        >{{ hbBadge() }}</span
      >
    }
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    role: 'tab',
    '[class]': 'classes()',
    '[id]': 'ctx?.tabId(hbValue())',
    '[attr.aria-selected]': 'active()',
    '[attr.aria-controls]': 'ctx?.panelId(hbValue())',
    '[attr.aria-disabled]': 'hbDisabled() || null',
    '[attr.data-state]': "active() ? 'active' : 'inactive'",
    '[attr.data-disabled]': 'hbDisabled() || null',
    '[attr.tabindex]': 'tabindex()',
    '[attr.disabled]': 'hbDisabled() || null',
    '(click)': 'onClick()',
    '(keydown)': 'onKeydown($event)',
  },
  exportAs: 'hbTab',
})
export class HbTabComponent {
  protected readonly ctx = inject<HbTabsContext | null>(HB_TABS, { optional: true });
  private readonly el = inject<ElementRef<HTMLElement>>(ElementRef);
  private readonly destroyRef = inject(DestroyRef);

  readonly hbValue = input<unknown>(null);
  readonly hbDisabled = input(false, { transform: booleanAttribute });
  readonly hbIcon = input<string>('');
  readonly hbBadge = input<string | number | null>(null);
  readonly class = input<ClassValue>('');

  private readonly ref: HbTabTriggerRef = {
    value: () => this.hbValue(),
    element: () => this.el.nativeElement,
    disabled: () => this.hbDisabled(),
  };

  protected readonly active = computed(() => (this.ctx ? this.ctx.isActive(this.hbValue()) : false));
  protected readonly tabindex = computed(() => {
    if (this.hbDisabled()) return -1;
    return this.active() ? 0 : -1;
  });
  protected readonly classes = computed(() =>
    cn(
      tabTriggerVariants({ size: this.ctx?.size() ?? 'md', variant: this.ctx?.variant() ?? 'line' }),
      this.class(),
    ),
  );

  constructor() {
    this.ctx?.registerTrigger(this.ref);
    this.destroyRef.onDestroy(() => this.ctx?.unregisterTrigger(this.ref));
  }

  protected onClick(): void {
    if (!this.hbDisabled()) this.ctx?.select(this.hbValue());
  }
  protected onKeydown(event: KeyboardEvent): void {
    this.ctx?.onTriggerKeydown(this.ref, event);
  }
}

import { Directive } from '@angular/core';

@Directive({ selector: '[hbTabsIndicator]' })
export class HbTabsIndicatorDirective {}

import {
  booleanAttribute,
  computed,
  contentChild,
  Directive,
  input,
  model,
  numberAttribute,
  output,
  signal,
  TemplateRef,
} from '@angular/core';

import { type ClassValue } from '{{alias}}/utils';
import { HbTabsIndicatorDirective } from './tabs-indicator.directive';
import { type HbTabsContext, type HbTabTriggerRef } from './tabs.token';
import {
  type HbTabsActivationMode,
  type HbTabsAlign,
  type HbTabsOrientation,
  type HbTabsPosition,
  type HbTabsSize,
  type HbTabsVariant,
} from './tabs.variants';

let tabsUid = 0;

const slug = (v: unknown): string => String(v).replace(/[^\w-]+/g, '-');

@Directive()
export abstract class HbTabsBase implements HbTabsContext {
  protected readonly uid = ++tabsUid;

  readonly hbValue = model<unknown>(undefined);
  readonly hbDefaultValue = input<unknown>();
  readonly hbVariant = input<HbTabsVariant>('line');
  readonly hbSize = input<HbTabsSize>('md');
  readonly hbPosition = input<HbTabsPosition>('top');
  readonly hbAlign = input<HbTabsAlign>('start');
  readonly hbActivationMode = input<HbTabsActivationMode>('automatic');
  readonly hbShowArrows = input(false, { transform: booleanAttribute });
  readonly hbScrollThreshold = input(0, { transform: numberAttribute });
  readonly hbIndicatorClass = input<ClassValue>('');
  readonly class = input<ClassValue>('');

  readonly hbChange = output<unknown>();

  protected readonly indicatorTpl = contentChild(HbTabsIndicatorDirective, { read: TemplateRef });

  private readonly triggerList = signal<HbTabTriggerRef[]>([]);

  readonly variant = this.hbVariant;
  readonly size = this.hbSize;
  readonly position = this.hbPosition;
  readonly align = this.hbAlign;
  readonly activationMode = this.hbActivationMode;
  readonly showArrows = this.hbShowArrows;
  readonly scrollThreshold = this.hbScrollThreshold;
  readonly orientation = computed<HbTabsOrientation>(() =>
    this.hbPosition() === 'left' || this.hbPosition() === 'right' ? 'vertical' : 'horizontal',
  );

  value = (): unknown => {
    const v = this.hbValue();
    if (v !== undefined && v !== null) return v;
    const d = this.hbDefaultValue();
    if (d !== undefined && d !== null) return d;
    return this.triggerList().find((t) => !t.disabled())?.value();
  };
  isActive(value: unknown): boolean {
    return this.value() === value;
  }
  select(value: unknown): void {
    const trigger = this.triggerList().find((t) => t.value() === value);
    if (trigger?.disabled()) return;
    this.hbValue.set(value);
    this.hbChange.emit(value);
  }

  indicatorTemplate = (): TemplateRef<unknown> | null => this.indicatorTpl() ?? null;
  indicatorClass = (): ClassValue => this.hbIndicatorClass();

  registerTrigger(trigger: HbTabTriggerRef): void {
    this.triggerList.update((list) => [...list, trigger]);
  }
  unregisterTrigger(trigger: HbTabTriggerRef): void {
    this.triggerList.update((list) => list.filter((t) => t !== trigger));
  }
  triggers = (): HbTabTriggerRef[] => this.triggerList();

  private ordered(): HbTabTriggerRef[] {
    return [...this.triggerList()].sort((a, b) =>
      a.element().compareDocumentPosition(b.element()) & Node.DOCUMENT_POSITION_FOLLOWING ? -1 : 1,
    );
  }
  onTriggerKeydown(trigger: HbTabTriggerRef, event: KeyboardEvent): void {
    const enabled = this.ordered().filter((t) => !t.disabled());
    const i = enabled.indexOf(trigger);
    const horizontal = this.orientation() === 'horizontal';
    const prev = horizontal ? 'ArrowLeft' : 'ArrowUp';
    const next = horizontal ? 'ArrowRight' : 'ArrowDown';
    let target: HbTabTriggerRef | undefined;
    switch (event.key) {
      case prev:
        target = enabled[(i - 1 + enabled.length) % enabled.length];
        break;
      case next:
        target = enabled[(i + 1) % enabled.length];
        break;
      case 'Home':
        target = enabled[0];
        break;
      case 'End':
        target = enabled[enabled.length - 1];
        break;
      case 'Enter':
      case ' ':
        event.preventDefault();
        this.select(trigger.value());
        return;
      default:
        return;
    }
    if (!target) return;
    event.preventDefault();
    target.element().focus();
    if (this.hbActivationMode() === 'automatic') this.select(target.value());
  }

  tabId(value: unknown): string {
    return `hb-tabs-${this.uid}-tab-${slug(value)}`;
  }
  panelId(value: unknown): string {
    return `hb-tabs-${this.uid}-panel-${slug(value)}`;
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  forwardRef,
  ViewEncapsulation,
} from '@angular/core';

import { cn } from '{{alias}}/utils';
import { HbTabsBase } from './tabs.base';
import { HB_TABS } from './tabs.token';
import { tabsRootVariants } from './tabs.variants';

@Component({
  selector: 'hb-tabs',
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    '[class]': 'rootClasses()',
    '[attr.data-slot]': "'tabs'",
    '[attr.data-position]': 'hbPosition()',
  },
  providers: [{ provide: HB_TABS, useExisting: forwardRef(() => HbTabsComponent) }],
  exportAs: 'hbTabs',
})
export class HbTabsComponent extends HbTabsBase {
  protected readonly rootClasses = computed(() =>
    cn(
      tabsRootVariants({ position: this.hbPosition() }),
      this.orientation() === 'vertical' && 'items-start',
      this.class(),
    ),
  );
}

import { HbTabListComponent } from './tab-list.component';
import { HbTabMenuComponent } from './tab-menu.component';
import { HbTabPanelComponent } from './tab-panel.component';
import { HbTabComponent } from './tab.component';
import { HbTabsComponent } from './tabs.component';
import { HbTabsIndicatorDirective } from './tabs-indicator.directive';

export const HbTabsImports = [
  HbTabsComponent,
  HbTabListComponent,
  HbTabComponent,
  HbTabPanelComponent,
  HbTabMenuComponent,
  HbTabsIndicatorDirective,
] as const;

import { InjectionToken, type TemplateRef } from '@angular/core';

import type { ClassValue } from '{{alias}}/utils';
import type {
  HbTabsActivationMode,
  HbTabsAlign,
  HbTabsOrientation,
  HbTabsPosition,
  HbTabsSize,
  HbTabsVariant,
} from './tabs.variants';

export interface HbTabTriggerRef {
  value: () => unknown;
  element: () => HTMLElement;
  disabled: () => boolean;
}

export interface HbTabsContext {
  value: () => unknown;
  isActive(value: unknown): boolean;
  select(value: unknown): void;

  variant: () => HbTabsVariant;
  size: () => HbTabsSize;
  position: () => HbTabsPosition;
  orientation: () => HbTabsOrientation;
  align: () => HbTabsAlign;
  activationMode: () => HbTabsActivationMode;

  showArrows: () => boolean;
  scrollThreshold: () => number;
  indicatorTemplate: () => TemplateRef<unknown> | null;
  indicatorClass: () => ClassValue;

  registerTrigger(trigger: HbTabTriggerRef): void;
  unregisterTrigger(trigger: HbTabTriggerRef): void;
  triggers: () => HbTabTriggerRef[];
  onTriggerKeydown(trigger: HbTabTriggerRef, event: KeyboardEvent): void;

  tabId(value: unknown): string;
  panelId(value: unknown): string;
}

export const HB_TABS = new InjectionToken<HbTabsContext>('HB_TABS');

import { cva, type VariantProps } from 'class-variance-authority';

export type HbTabsPosition = 'top' | 'bottom' | 'left' | 'right';
export type HbTabsVariant = 'line' | 'pills' | 'underline';
export type HbTabsSize = 'xs' | 'sm' | 'md' | 'lg' | 'xl';
export type HbTabsAlign = 'start' | 'center' | 'end' | 'stretch';
export type HbTabsActivationMode = 'automatic' | 'manual';
export type HbTabsOrientation = 'horizontal' | 'vertical';

export const tabsRootVariants = cva('flex', {
  variants: {
    position: {
      top: 'flex-col',
      bottom: 'flex-col-reverse',
      left: 'flex-row',
      right: 'flex-row-reverse',
    },
  },
  defaultVariants: { position: 'top' },
});

export const tabListVariants = cva('relative flex', {
  variants: {
    orientation: { horizontal: 'flex-row items-stretch', vertical: 'flex-col items-stretch' },
    variant: {
      line: '',
      pills: 'gap-1 rounded-lg bg-muted p-1',
      underline: '',
    },
    align: {
      start: 'justify-start',
      center: 'justify-center',
      end: 'justify-end',
      stretch: '[&>[role=tab]]:flex-1',
    },
  },
  defaultVariants: { orientation: 'horizontal', variant: 'line', align: 'start' },
});

export const tabTriggerVariants = cva(
  'relative z-10 inline-flex shrink-0 cursor-pointer items-center justify-center gap-2 font-medium whitespace-nowrap outline-none transition-colors focus-visible:ring-[3px] focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50 text-muted-foreground data-[state=active]:text-foreground [&_ng-icon]:shrink-0',
  {
    variants: {
      size: {
        xs: 'h-7 gap-1.5 px-2 text-xs [&_ng-icon]:text-sm',
        sm: 'h-8 px-2.5 text-xs [&_ng-icon]:text-base',
        md: 'h-9 px-3 text-sm [&_ng-icon]:text-lg',
        lg: 'h-10 px-4 text-sm [&_ng-icon]:text-xl',
        xl: 'h-11 px-5 text-base [&_ng-icon]:text-2xl',
      },
      variant: {
        line: 'rounded-md',
        pills: 'rounded-md',
        underline: '',
      },
    },
    defaultVariants: { size: 'md', variant: 'line' },
  },
);

export type HbTabsSizeVar = NonNullable<VariantProps<typeof tabTriggerVariants>['size']>;

